INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间非常好 装修很厚重奢华 一开始看评论 看酒店自己po的照片 感觉跟快捷酒店一', '房间非常好 装修很厚重奢华 一开始看评论 看酒店自己po的照片 感觉跟快捷酒店一样 有些害怕  但来了之后 真的很惊喜 装修很厚重 很奢华 跟一些老牌的日系酒店 （帝国酒店）之类的感觉 没想到在广州也有这样开业时间很长但仍然配套跟得上的酒店。。
服务很好！ 门童拿行李迎宾开门 比一些国际连锁的五星要好多了。 退房时候liren还帮忙直接登记了退房 不用排队了。什么时候北京的酒店服务也能跟上广州呢。。。

另外吃的真的很好

晚上去楼顶旋转自助吃 螃蟹腿鲍鱼进口生蚝 吃撑了 还有最爱吃的金蒜牛肉 做的真的很好吃 比北京第六季那种什么海鲜都拿来涮的自助强好多

酒店里还有花园 大锦鲤吃的真的好 又大又肥

总体来说 物超所值  下次还来', '2025-04-05', 5, '[''整体满意度'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230y12000jkw8gdf4A0A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p12000jkw8c5xF397_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230112000jkw939u15B4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234q12000jkvndawCBC2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233k12000jkvsb4g1234_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231m12000jkvk75x709D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232v12000jkvf2xf4D38_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230p12000jkufeze39FC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236012000jkura218677_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店广州的老牌五星，一直期望的入住。房间我入住时要求前台帮我升级了新装修的房', '花园酒店广州的老牌五星，一直期望的入住。房间我入住时要求前台帮我升级了新装修的房间，粤韵。其他的房型是没装修过的。房间大，干净，就是卫生间没隐私，换衣服要躲在淋浴房里才行。其他的环境设置泳池，都挺好，服务员服务水平一般，没有白天鹅感受的温暖，感觉有点冷冷的。外国人很多，地铁口离酒店门口有一点点距离，步行6-7分钟。早餐很用心，菜品昧道很赞。家庭亲子不建议，可以来吃饭，住就可以选其他更好的，白天鹅宾馆新装修的，房型很不错。建议花园酒店参考改进。', '2025-04-07', 4, '[''房间设施'', ''整体满意度'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0234612000jml1bu97948_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232v12000jmlltnv9C48_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000jmlwvj27D09_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235l12000jmla5r8B949_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231512000jmlt43f8C15_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233a12000jmljk7w3D88_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235z12000jmlqsjnC28A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234n12000jmlltnz635C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236812000jml0ofx32FD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一进酒店就感觉来到了桃花源，迎宾人员都很热情，彬彬有礼，房间也非常不错，床品都很', '一进酒店就感觉来到了桃花源，迎宾人员都很热情，彬彬有礼，房间也非常不错，床品都很舒服，洗嗽用品的香味很好闻！还有旋转自助餐厅非常不错，食材品质都很好，厨师手艺在线！四楼的还有个酒店博物馆值得一去！最后感谢携程推荐了这么好的酒店！下次来广州还住这里！', '2025-04-15', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230112000jtm270m91CD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000jtl7c8n322A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000jtmmrhc9D05_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231f12000jtmfku7DC66_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236v12000jtmc1eh29DB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000jtlbtxw3284_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000jtl7q7304D1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233712000jtmfkub6EF8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235j12000jtmmrhg0A67_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '总体来说很好。早餐有两个地方可以用，最上层的旋转餐厅用早餐感觉还是非常不错的。另', '总体来说很好。早餐有两个地方可以用，最上层的旋转餐厅用早餐感觉还是非常不错的。另外酒店的后花园也挺好，硕大的锦鲤鱼??甚是好看。酒店四楼的“酒店博物馆”再次惊到我，内容非常丰富，不愧是钻石五星酒店。', '2025-04-15', 5, '[''餐饮设施'', ''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231r12000jtfoc894D7B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000jti1meo5C49_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230112000jthv7clA49D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '多年没来广州，临时起意过来住花园酒店，环境舒适，没有想象中的老式，全员服务在线，', '多年没来广州，临时起意过来住花园酒店，环境舒适，没有想象中的老式，全员服务在线，礼貌周到，给顾客一种所有员工都在朝着让客人满意的方向努力的感觉，也因此使得本来因夜里市政修路产生噪音而换房的麻烦也显得没那么让人烦躁了。 订的双早，入住的时候小姐姐给小孩也赠送了早餐，客房服务速度很快，整个入住体验如沐春风不为过，担得起广州地标的称誉', '2025-04-06', 5, '[''整体满意度'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231o12000jm0k1l221A4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000jm1p6xfBBB4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234412000jm0wxnz0DD8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233e12000jm133ibF8B5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231j12000jm1g63tBCFD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235n12000jm0nrai5C3C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店环境很好，房间干净整洁，视野不错。酒店的后花园挺漂亮的，可以逛逛。附近买吃的', '酒店环境很好，房间干净整洁，视野不错。酒店的后花园挺漂亮的，可以逛逛。附近买吃的也方便。
美中不足的因为少带充电线，但是酒店借的充电线是完全不能用的，和酒店服务部说明后，工作人员说没有多余的充电线了。好在可以借充电宝或在酒店的迷你超市买充电线。
总体来说是不错的体验。', '2025-04-06', 5, '[''卫生状况'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/02355224x90fb4hhv9F3F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f224x90fae98s4408_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y224x90fam7nr57BB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02369224x90fa89ha04CF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02312224x90fc1xvn7124_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '有集团金卡可以免费升级房型，酒店装修过非常的漂亮，后花园很大，景色很好。早餐非常', '有集团金卡可以免费升级房型，酒店装修过非常的漂亮，后花园很大，景色很好。早餐非常好吃，电梯很多不用等。服务态度也很好，大厅的人员很多，去哪里都有人主动上来招待。礼宾部寄存行李的地方态度很好，速度很快。', '2025-04-04', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231m12000jk0k7md2563_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店房间上放着餐厅有75折扣优惠，并且没有写有截至时间，但是去餐厅用完餐就被告知', '酒店房间上放着餐厅有75折扣优惠，并且没有写有截至时间，但是去餐厅用完餐就被告知已经没有优惠了，这个餐饮优惠活动没有和客房服务能够同步非常让人失望，对我们住店客户有很大的误导性。
客房打扫人员，每天都把使用过的牙膏扔掉，这个浪费很大，本来牙膏在没有使用完我都还可以继续使用，现在只能每天都开个新的牙刷牙膏套装，非常不环保和浪费。建议牙膏牙刷分开装，客户自己没有扔掉服务员不要帮扔。', '2025-04-04', 4, '[''餐饮设施'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235l12000jjk05i0780F_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店服务相当不错，很有礼貌，入住和退房是挺快的。入住时还送了两朵康乃馨。不值钱，', '酒店服务相当不错，很有礼貌，入住和退房是挺快的。入住时还送了两朵康乃馨。不值钱，但是心意是有的。如果房间配个花瓶会更好，我们是用杯子插的。
酒店古色古香，像是行走中的博物馆，而且4楼真的有一个博物馆。介绍了很多酒店的历史，值得参观。博物馆是7点结束，所以要早点去。
自助点心晚餐和自助早餐都还不错，个人对自助点心晚餐是比较满意的，品质味道都有保证，我特别喜欢芋角和麻薯。女儿就非常喜欢吃牛百叶，吃了五笼。
我比较喜欢吃面包，但是自助早餐的面包有点让我失望。其他还是可以的。
最重要的房间，也是我没想到的，床头就是冲凉房，冲凉房就是一个浴缸，直接上浴缸。而且厕所门是同一个冲凉就不能上厕所，上厕所就不能冲凉。蛮尴尬的。
床和枕头还是蛮舒服的。
但电视机没办法投屏，有时候想看一些手机上的剧，想投到电视上就没办法。
看来我们住的是比较便宜的房间，所以比较小，我看到网上红棉房那个房型是比较好的，但是价格贵。
有钱建议还是订红棉房。', '2025-02-12', 5, '[''房间设施'', ''前台服务'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0233q12000ihkzye7D554_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y12000ihlct4l2456_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230812000ihl3x47F9AB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233012000ihl55so1212_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231212000ihljihh0E49_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233g12000ihkvn8k89F7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235d12000ihlfqgg3CA3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235e12000ihlilg5DD0F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235812000ihl9atsBF2A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间硬件不错，服务、餐饮不及格，沟通好的生日主题布置，居然忘记了！提醒前台以后特', '房间硬件不错，服务、餐饮不及格，沟通好的生日主题布置，居然忘记了！提醒前台以后特意离开房间给工作人员布置，结果回房间一看，蛋糕没有，一问，原来送到别人的房间去了！无语！所谓的瀑布餐厅的早餐，更加无语！排队就算了！里面的菜品不如快捷酒店！2百多一位的早餐 和其他酒店38元一位的差不多！咖啡还没快捷酒店的好！至于荔湾亭的好评绝对是花钱买的！全部扎扎实实的预制菜！隐形消费多！吃顿饭补了3次钱！自助餐居然茶位费需要另付！白开水也要18元一位！', '2025-03-30', 3, '[''餐饮设施'', ''前台服务'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0231x12000jf5r5l88FF8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很喜欢花园酒店，服务好，帮我们升级了房间，房间宽敞干净，住着舒服；早餐供应时间长', '很喜欢花园酒店，服务好，帮我们升级了房间，房间宽敞干净，住着舒服；早餐供应时间长，品种丰富味道好，就是小孩子6岁就要买半价早餐，114/位确实确实贵；套餐里送的荔湾亭餐厅的晚餐很好吃，我们全家都非常喜欢，每天晚上都吃撑了哈哈；酒店是名副其实的花园酒店，早餐厅能看到外面后花园的瀑布，花园很漂亮，小朋友每天都要去逛一圈。
唯一美中不足的就是楼下地铁施工确实吵，晚上感觉要折腾到11、2点，早上6点就又开始了，不过这也不是酒店能控制的。
还有一个小插曲就是我明明在携程上预定了两晚，但不知道为什么办入住的时候就给我办了一晚，第二天打电话问我退不退房，回去之后又重新激活房卡，工作人员也没有表达任何歉意，这个让我感受不太好。
不过总体而言，我还是满意的，以后地铁修好了还可以住。', '2025-03-21', 5, '[''整体满意度'', ''餐饮设施'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236q12000j89v1ni0D4F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233n12000j8ann7iED2C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231i12000j8anos1C409_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234912000j8agz5e974E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234712000j89vghtDE19_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232x12000j8ar2id5343_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235t12000j8a0eiuE917_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234t12000j8a2yue912F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000j8a9pr2C8CD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店不愧是老牌五星级酒店，一如既往的服务至上，里面装修跟十年前一样酒店维', '广州花园酒店不愧是老牌五星级酒店，一如既往的服务至上，里面装修跟十年前一样酒店维护的很好，入住的办理的小姑娘Betty特别不错尽心满足我们的需求，由于到达酒店已经有点晚了没有来得及享用套餐里面的下午茶，Betty马上跟主管联系把我们下午茶改成第二天的，第二天的下午茶在行政酒廊环境很是怡人隔着玻璃就可以看见酒店花园瀑布，工作人员Louis Cathy服务周到细心，凌璇阁的自助餐品质非常棒！下次一定会再次选择广州花园酒店！', '2025-03-30', 5, '[''前台服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236t12000jf8ywf3CF63_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000jf84ykw5ACB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000jf8hqu50E0E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：老牌五星酒店设施，不算特别新但是够用，床品还算舒服。', '设施：老牌五星酒店设施，不算特别新但是够用，床品还算舒服。
卫生：卫生很好，屋内收拾的特别干净。
环境：后花园太美了，好多锦鲤还有瀑布，带孩子转了好几圈，特别开心。
服务：服务员非常好，帮忙开车拿行李，开门，开电梯。很棒。', '2025-03-31', 5, '[''整体满意度'', ''卫生状况'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233n12000jg7bw8g2F3B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000jg6troe70BC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000jg6t4sh4648_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '旅游入住了广州花园酒店，体验感超棒！一进大堂，挑高设计搭配华丽吊灯，瞬间被震撼。', '旅游入住了广州花园酒店，体验感超棒！一进大堂，挑高设计搭配华丽吊灯，瞬间被震撼。前台办理入住迅速，员工热情贴心，还详细介绍酒店设施。退房时Tina小姐姐十分迅速帮忙快速退房，一点没耽误行程。

房间布置典雅，床品舒适，窗外景色也不错。迷你吧饮品丰富，洗浴用品品质高。

酒店餐饮绝绝子，桃园馆的早茶，虾饺、肠粉新鲜又美味。自助餐厅海鲜新鲜，甜品精致。

健身房器材新且全，泳池水质清澈。位置也很优越，周边交通便利，商场、景点近。下次来广州，肯定还选这儿！', '2025-04-06', 5, '[''整体满意度'', ''前台服务'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0233i12000jlxw21n1EC3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '虽然是老牌酒店但设施并不显得陈旧，房间卫生，停车方便，离淘金地铁站很近，交通非常', '虽然是老牌酒店但设施并不显得陈旧，房间卫生，停车方便，离淘金地铁站很近，交通非常方便，花园、瀑布和池塘里的锦鲤令人赏心悦目。酒店工作人员LiVen服务态度很好，热情细心的答复我的疑问和帮忙办理入住和退房，点个赞????', '2025-04-05', 5, '[''交通便利性'', ''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235s12000jkvm01eCF03_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000jkvqybo97E0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000jkvw1ud52F6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：房间翻新过，给了升级，面向小区的，晚上睡觉特别安静，真的是住过的最舒服的床', '设施：房间翻新过，给了升级，面向小区的，晚上睡觉特别安静，真的是住过的最舒服的床！！ ，音响也用的JBL ，超棒的音效

服务：快来夸夸服务！ 入住当天去了酒廊，有两位女士真的服务很热情，都有点不好意思了，一站起来就嘘寒问暖，各种主动提供需求可能，这才是水准 ，表扬Carrie～ 还有louis ，Carrie是位外籍人士，真的很认真，也是我第一次在酒店遇到，还推荐我去博物馆，专业且不失风度
还有前台的两位小姑娘，闪闪亮亮，退房的时候主动迎上来问，说把房卡给她们就好，而且还特别的温柔，很是酒店的门面，是Lulu和Liven

但唯一给差评的就是酒店的自助餐！ 在某某点评已经写了，就不多赘述，体验感直接打折，好在有这些服务人员的努力才能挽回，下次还回来', '2025-04-13', 5, '[''前台服务'', ''房间设施'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231e12000jrrku8e3C75_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000jrra5uh7C50_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次花园酒店给我的体验非常的美好。', '这次花园酒店给我的体验非常的美好。
设施：保护的非常的好。博物馆真是叹为观止。
荷花园小巧玲珑。瀑布餐厅依然是那样震撼又浪漫。李湾餐厅和桃园餐厅的美食。令人惊艳回味。

行政走廊的三位小姐姐。笑容可掬，服务周到。特别是beryle 令我印象深刻。
这次入住负责卫生的外国小姐姐。亲切有礼，收拾了房间非常的精致，还给我留了纸条。特此展出，提出表扬。', '2025-03-27', 5, '[''整体满意度'', ''客房服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230z12000jd3o2gyA90B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000jd3oen4D10E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232j12000jd3u0w53670_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232d12000jd3z59v43A4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233112000jd2svl53D40_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231u12000jd3ve9bF38C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '因为是老酒店，有很深的岭南文化底蕴，酒店的后花园别有特色，流水瀑布九曲长廊，一步', '因为是老酒店，有很深的岭南文化底蕴，酒店的后花园别有特色，流水瀑布九曲长廊，一步一景美轮美奂。我已经住过多次，印象最深的是酒店的服务人员，无论是做什么的，都能体现出专业的素质。', '2025-04-10', 5, '[''整体满意度'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234w12000jp90lmmD17E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233b12000jp89s272057_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230p12000jp8kgki5190_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231g12000jp9gmhe259E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234l12000jp8486f9601_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232112000jp8mtne2068_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次广州踏青之旅，基于情怀思量，选择入住花园酒店，没有选错；从进入大堂开始遇到的', '这次广州踏青之旅，基于情怀思量，选择入住花园酒店，没有选错；从进入大堂开始遇到的每位服务人员都热情和专业，特别是前台接待和行李寄存服务；酒店房间干净卫生温馨, 窗外可以看到瀑布，花团锦簇风景优美；酒店餐饮选择丰富，美景美食完美搭配；入住期间，参观了酒店的博物馆，浓厚的酒店历史和文化氛围，印象深刻，获益匪浅；有历史，有担当，有传承，白金五星酒店的称号实至名归。感谢酒店前台Winnie Yu的服务，热心细致，温文尔雅， 不愧是优质酒店培养出来的优秀服务人员，谢谢 ! 下次来广州，还选花园。', '2025-04-06', 5, '[''前台服务'', ''整体满意度'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0231512000jlswp15FC4A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000jlti21y4F49_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232m12000jltcs2v2E40_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236c12000jlsq42rF797_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237212000jls62l24096_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230o12000jlsqcmf6AFA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间够大～布局合理～餐食美味～一四楼的酒店博物馆很有历史年代感～天气凉没下水～泳', '房间够大～布局合理～餐食美味～一四楼的酒店博物馆很有历史年代感～天气凉没下水～泳池还是很不错滴后花园很出片～最喜欢的是酒店到处都是鲜花布置～体现了广州花都的花园酒店～非常完美的一次选择～', '2025-03-10', 5, '[''整体满意度'', ''房间设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232a12000iz89p3m15F6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234z12000iz91e6p95F5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000iz8h6qs79E0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234e12000iz8o2t0F1F4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y12000iz90tat11BE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230l12000iz9hivm4ABE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231112000iz8fb9x02AE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000iz8cxjpA3D8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233b12000iz7bok4D7B4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '跨越16小时航程的温暖归家——广州花园酒店极致体验', '跨越16小时航程的温暖归家——广州花园酒店极致体验

当行李箱轮子与广州白云机场T2航站楼地面接触的那一刻，连日的疲惫都在看到"广州花园酒店"迎宾灯牌的瞬间消散。作为一家在异国漂泊数十载后重返故土的游子，这家承载着城市记忆的五星级酒店，用超越期待的服务为我们构筑了最动人的归家仪式。

初遇即感动：Ann女士的"宾至如归"方程式
推开通往大堂的旋转门，身着香槟色制服的Ann女士早已伫立在晨光中。她接过我们的证件时特意调整至45度躬身角度，这个细微动作让刚下飞机的我们倍感尊重。"您二位应该需要先补充能量，"她指着自助早餐区暖黄色的灯光轻声建议，"我们的港式丝袜奶茶刚出炉，配您预订的招牌叉烧包正好。"更令人惊喜的是，在办理入住时她主动递来升级房卡："行政楼层今天正好有空房，考虑到您二位的长途旅程，特别为您预留了景观房。"这份预见性服务让我们还未踏入房间就已感受到被珍视的幸福。

沉浸式体验：藏在细节里的东方待客之道
踏入25层行政套房那一刻，扑面而来的岭南花茶香构成了独特的欢迎仪式。房间明亮宽敞，设计特具中国传统，就连空调出风口都萦绕着淡淡的白茶香——这些看似微不足道的细节，实则是本土化服务的精髓所在。当客服轻轻推开房门送上新鲜水果时，我们真切理解了何为"润物细无声"的关怀。

舌尖上的乡愁：米其林星厨演绎广府美食
位于酒店三层的桃园厅为住客精心安排广式早茶点心，更是唤醒了童年的回忆。最令人难忘的虾饺烧卖，每一口都是地道的广式甜蜜。

离别时的不舍：镌刻在时光里的美好，我们相约来年的相聚
这不仅仅是一次住宿体验，更是一场穿越时空的文化对话。从大堂穹顶的岭南园林壁画，到客房迷你吧里香茶，到行政酒廊的珠江夜景鸡尾酒——广州花园酒店用百年匠心诠释着何为"家外之家"。特别感谢Ann女士及其团队，他们让我们在16小时飞行后找回了作为广州人的文化认同与归属感。相信这座岭南明珠，必将继续以东方待客之道的精髓，为每一位远道而来的游子点亮归途的明灯。', '2025-03-23', 5, '[''前台服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230612000j9qrb9q8040_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p12000j9stgq8A111_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000j9rjxjr9460_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第二次入住广州花园酒店，进门就闻到了熟悉的香氛味道。广交会期间客人很多，但酒店工', '第二次入住广州花园酒店，进门就闻到了熟悉的香氛味道。广交会期间客人很多，但酒店工作人员基本应对自如，忙碌且有序。2点准时入住，这次入住红棉双床套房，中式装修风格，更适合国人审美房间面相花园和泳池景观。恰逢阴雨大风天气，下午在一楼行政酒廊下午茶+欢乐时光，看着窗外的风雨交加和云卷云舒，很惬意。晚餐在30楼的凌璇阁，住店客人可享5折优惠，最近也有凭景点打卡记录享餐厅买一赠一活动。至于餐食和口味，倒是没有特别惊艳。第二天早餐后大堂小何帮办理了快捷退房，小郑经理介绍了????羊羊吉祥物，忍不住入手了龙年限定版??图14，照例逛了后花园和4楼博物馆，可谓花园酒店的精髓。嗯，下次还来！', '2025-04-13', 5, '[''整体满意度'', ''景观/朝向'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236o12000jrkquvk8A62_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233a12000jrkxd1m576B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234612000jrl5yjgBF72_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000jrl00r306F2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234u12000jrkvpru2871_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000jrkx4xz9E34_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000jrl0le3D3A6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h12000jrl0b3j9A4A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000jrl0ycf0C08_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '每次到广州出差都会选择花园酒店，首先老牌五星酒店值得信赖，再加服务方面确实比较扎', '每次到广州出差都会选择花园酒店，首先老牌五星酒店值得信赖，再加服务方面确实比较扎实，感谢前台接待CECILIA，办理入住非常热情周到，还要感谢一下行政酒廊的，Carrie跟Kitty,服务都是很热情周到，让每一位旅客感觉到宾至如归的感觉，下次来广州依然会选择花园酒店！！！', '2025-03-18', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234u224x8zzey06b4865_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231g224x8zzfgjc61B15_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233x224x8zzfb1w8C166_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台对业务不太熟悉，入住第二晚在前台询问晚餐时间及价钱，前台两位工作人员都不知道', '前台对业务不太熟悉，入住第二晚在前台询问晚餐时间及价钱，前台两位工作人员都不知道（也可能是实习生），需打电话询问，且想当然的认为我们只是来吃饭的，导致信息有偏差。除此以外，都不错。', '2025-03-31', 4, '[''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233v12000jfwvh5mF82A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234612000jfwq0u26597_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233b12000jfwyea182B0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很好，符合预期，位置也很方便，距离商业圈很近，都是步行5分钟的距离。电梯好多', '房间很好，符合预期，位置也很方便，距离商业圈很近，都是步行5分钟的距离。电梯好多我有点迷糊～35块钱包minibar部分软饮我觉得是比较划算的，前台送了玫瑰花和冰箱贴，很美～', '2025-04-09', 5, '[''性价比'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231b12000jnuk1253355_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231q12000jnutmuhB564_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000jntdply8252_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店环境幽雅别致。', '花园酒店环境幽雅别致。
服务：服务满意
卫生：满意
荔湾亭茶点满意
早餐一层就餐人较多，需要等位。早餐菜品不是很多。四层博物馆需要预约，值得去。还有文创产品。目前酒店旁边有工地装修有点减分。酒店离淘金地铁站很近，去东山口就两站地很方便，很多景区地铁都直达。打车也很方便。酒店离市区必逛的景区都很近。酒店是涉外酒店，外国人较多。', '2025-03-18', 4, '[''交通便利性'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236312000j5bg1rhD140_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000j5bzfer9B1B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230h12000j5b7aucDF6F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p12000j5buo8rAEE0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000j5brvduB881_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233k12000j5cde2k1DB5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境：整体酒店环境设计很好，瀑布和花园很有特色，贝聿铭的设计是加分项，酒店博物馆', '环境：整体酒店环境设计很好，瀑布和花园很有特色，贝聿铭的设计是加分项，酒店博物馆也用心了，不住也可也来逛逛拍照。老牌五星级酒店的水准还在，只是房间内有些年代留下的痕迹，酒店房间也在逐步更新，外围有修地铁施工确实噪音影响很大，临近的房间影响休息，广州规定是早七晚十可施工，但施工单位违规，投诉效果不佳，酒店也有做提示。
服务：五星酒店的服务没得挑，携程铂金会员给升级了岭南金卡会员的优待，升了房型，因为室内空气和室外噪音问题，客服部帮忙换了两次房间，还赠送了早餐，客户的诉求相应很快，会员让人有再次入住的想法。
早餐：一层和三十层的早餐都是自助，种类差不多，不太符合美食之都五星酒店该有的水准，味道中规中矩。一层八点半后人很多，需要等位。三十层位置少，可远眺城景，安静很多。三层是套餐，座位有限，最好预约一下，这次没吃到。
设施：床品很好，舒服，可按需求选枕头，行政大床房的床垫是乳胶的，自带角度，非常好。洗漱用品的品牌和五星不太匹配，使用上没什么问题。', '2025-02-23', 5, '[''安静程度'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230f12000iozprh779FF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230e12000iozql0w0C78_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000ioyud535309_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235p12000ioyyyr7F504_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236512000ioz3cqq3C71_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232712000iozp45m9135_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232i12000ioz7jkmA0DE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234012000iozp13c4718_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i12000iozk2kq5090_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '怎么说呢，', '怎么说呢，
冲着酒店历史和硬件来的
美中不足的是第一天入住就给我搞得3点办理完成
我定了三间房间，全部全部冲施工方向
最后给我更换了
后花园很美丽
鱼都养的胖胖的', '2025-04-11', 4, '[''退房/入住效率'', ''景观/朝向'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235f12000jpv6oidF806_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000jptshxc5841_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '作为一家老牌白金五星级酒店，酒店环境依然是酒店门面。', '作为一家老牌白金五星级酒店，酒店环境依然是酒店门面。

设施：刚到房间就遇到打不开门，又要跑下楼找前台，前台服务人员非常积极应对，并及时找工作人员上楼查看，原来门把手要反使用习惯先向上提一下再往下按才打得开门，可之后进出又不用先向上提了。房间内的设施就真的让人大跌眼镜！首先图一可以看到洗手间和淋浴间是共用一扇门，但这扇门无论是在马桶那边还是在淋浴这边，门居然都是倾斜的！根本无法完全关闭，留着一条粗壮的门缝。其次浴缸的花洒托架也是松动的，从图二可见底托已经完全脱离了墙壁，感觉随时都会脱落下来。由此可见酒店平时就疏于对房间设施的有效维护。

卫生：图三是卫生间的墙角，坐在马桶上就能看到这厚厚的污渍，就这么看也有一年半载的量了吧。

服务：本来是想给三颗星的，原因晚上十一点半临时要开车出去，结果到大堂前厅办理停车票的时候居然发现整个前厅都没有工作人员！又要走进去大堂找前台服务人员帮忙，还要前台服务人员打电话给前厅的服务人员叫人过来，打完电话还要登了几分钟才有人来。最后给半颗星原因退房寄存行李后和家人朋友外出吃饭聊天直到下午四点多才回酒店拿行李并办理停车出场。结果在办理停车的时候这个叫     ROY    的服务人员一脸嫌弃的说我们不能办理停车，有人办理了。当时我们都莫名其妙一下子也都不明白啥意思。接着这个叫   ROY   的服务人员说一间房不能办理两台车，我们就更不懂了，明明我们才来办理怎么就不能办理呢？何况我们真的开了两台车过来。经过一番争论后原来是有其他人挂在我们房间下。而这位叫   ROY.   的服务人员也并没有表达歉意，并且由始至终都是一副厌烦的态度在对待我们。果真白金五星级酒店的待客之道就是有独特的见解。

相比2024年5月入住的时候整体水平可以用天差地别来形容。', '2025-03-12', 2, '[''房间设施'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0232l12000j1ais189254_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235h12000j1az6xv1AAD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230h12000j1b5fq0F936_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '三八妇女节遇上了阴冷天，咱来个投机取巧，选择了广州花园酒店，周六上午午饭后，步行', '三八妇女节遇上了阴冷天，咱来个投机取巧，选择了广州花园酒店，周六上午午饭后，步行进入酒店，前后还送了二枝??。这家酒店1985年营业至今四十年哦。依然保持着五星级水准，难能可贵是在酒店四层，开了个世界酒店史话主题的博物馆，里面珍藏品不少咧。酒店后花园也属于别具匠心精心布置有三个瀑布，锦鲤鱼池，小桥，鲜花朵朵草地绿油油的，地方不大小巧玲珑的。', '2025-03-09', 5, '[''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231d12000iyzfws6CA20_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0236y12000iyzfsyr7765_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '没想到我们自己国家也有歧视中国人的服务员。我和朋友排队等待进入餐厅吃早饭的时候，', '没想到我们自己国家也有歧视中国人的服务员。我和朋友排队等待进入餐厅吃早饭的时候，有四五个外国人一起排在我们前面，他们等候一分钟左右便入场。等我们排到队伍最前时，服务生说现在等候时间不确定，可能会等很久，建议我们去高层另一处早餐厅。我和朋友是为了一楼早餐厅山水景观专门来住宿、就餐，所以决定继续等待。期间服务员反复说“不确定等候多久，建议上楼就餐”，然而她们并没有和前面的外国人顾客说这些。并且，当我和朋友等待两三分钟入场后，发现早餐厅空位很多，尤其是水果餐区附近几乎没有几个客人。以后绝不会再来这家酒店。我不需要道歉，不需要解释，酒店餐厅不专业的服务已经说明了一切。', '2025-03-24', 0, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233y224x903ptspv5005_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '优点：', '优点：
酒店很大很漂亮，住的高层，窗外风景很棒。服务也很不错。离地铁站近，出门很方便。
酒店有历史底蕴，四楼有博物馆，展现了酒店业的发展，也让我种草了好多酒店，下次来广州一定要去体验。
不足：
办理入住排队时间较久；荔湾亭茶点一般，早餐还行，就是早餐要排队，瀑布餐厅着实小了点。
总体感觉还不错。', '2025-03-11', 4, '[''景观/朝向'', ''交通便利性'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0233u12000j01s2byF511_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233t12000j028m1o0E6E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000j01xd8y317F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店给我和孩子的感觉是一点都不像老酒店，不管是设施还是服务都特别不错，酒店当', '花园酒店给我和孩子的感觉是一点都不像老酒店，不管是设施还是服务都特别不错，酒店当天还免费给我们升级了房型，干净、温馨、大气。另外，店内荔湾亭的餐食也是不错的，瀑布餐厅的自助餐虽然品种较少，但其实我们想吃的食物也不会太多，也都能满足。谢谢花园酒店，让我和孩子三天两夜的广州之行过得非常愉快。PS：这也是一家有博物馆的酒店。', '2025-02-18', 5, '[''整体满意度'', ''房间设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233q12000ilmma6cFBFA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000ilm7a485DDC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232212000ilmd1blC804_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000ilmo9fj701A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i12000ilmsnhiA864_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233112000ilmn3y08483_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235612000illwniv7346_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g12000ilmaj9eBEAD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233e12000ilmoxq3E5E9_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌地标性酒店，独占好位置。酒店太大了，入住时有很多团队，是我办理check-i', '老牌地标性酒店，独占好位置。酒店太大了，入住时有很多团队，是我办理check-in最混乱的一次，带着老人也没有能休息的地方，也找不到引导人员，非常尴尬。好在房间不错，房间窗外能能远眺半截小蛮腰。两家餐厅桃园馆和荔湾亭的出品尚可，但是通过客服中心电话预定的桃园馆位置到场后却没有安排，那么预定的意义何在呢？早餐分一楼和顶楼，怕吵选了顶楼，出品很好，但顶楼的旋转餐厅坏了，能使用的餐台餐桌停在了非常丑的朝向位置上，有些可惜了广州的天际线。', '2025-03-09', 4, '[''前台服务'', ''景观/朝向'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231912000iyycci37823_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h12000iyy4q22A197_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233712000iyy8vpc7170_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店地址便捷，房间设施设备很齐全，已经续住很多天了，特别表扬前台的Win', '广州花园酒店地址便捷，房间设施设备很齐全，已经续住很多天了，特别表扬前台的Winnie wei 服务态度一级棒，还有前台lavinia .表扬她们，自信有笑容。以后一定再选择这个酒店', '2025-03-21', 5, '[''前台服务'', ''房间设施'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0233712000j7xt2ww1064_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000j7ypw6xA07B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000j7ytyhqDEC3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232812000j7x1o7536CA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '交通便利非常好，酒店国际化很多来自世界各地的游客和商务人士，酒店早餐3个餐厅选择', '交通便利非常好，酒店国际化很多来自世界各地的游客和商务人士，酒店早餐3个餐厅选择，种类多样。一楼大厅很大鲜花多样，酒店外面还有花园等景观，瀑布餐厅装修的非常好，来广州玩的两天很舒适，酒店服务也很棒！', '2025-03-10', 5, '[''交通便利性'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234h12000izo5swbD46B_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233q12000izo6v3g8D70_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232812000izo9koxE533_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '三十多年前的首选酒店，也是当时广州三家五星涉外酒店的首选！现在似乎有点老态龙钟了', '三十多年前的首选酒店，也是当时广州三家五星涉外酒店的首选！现在似乎有点老态龙钟了，花园还是一样的漂亮！但服务也还是觉对一流的，值得称赞??', '2025-03-22', 4, '[''整体满意度'', ''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/02360224x902mw7767EB4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233012000j8xt3rfCD0C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231s12000j8xd0bx6546_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233s12000j8xbfuxB904_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000j8wfo2e11D1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y12000j8wxwplBA6B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000j8xfpku0D48_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000j8x9e5n2947_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234d12000j8we660D938_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '我当时查阅携程就发现这是一家久负盛名的老酒店，很有历史感，又是贝聿铭先生的设计，', '我当时查阅携程就发现这是一家久负盛名的老酒店，很有历史感，又是贝聿铭先生的设计，一下子让我决定了就订这家了。到了酒店后，感觉都很心怡，确实是一家很棒的酒店。客人特别多，但是工作人员都特别亲切周到，没有忙乱，都是井井有条。check in时还升级了房间，特别惊喜，房间宽敞明亮，设施很好。无论酒店内外还是房间内的卫生都很不错，卫生肯定是一个酒店好坏的最重要的标准。再有就是这家酒店的餐饮超级棒，是非常值得来品尝的，广州特色美食特别丰富，真是让我们流连忘返，我们就餐时还看到餐厅里有很多当地的老人，可见实至名归啊。对了还有交通位置很不错，紧挨地铁站，去哪儿都方便。。。总之是很不错的广州之行。', '2025-03-27', 5, '[''整体满意度'', ''餐饮设施'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0236912000jcmfcjn28A4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234412000jcm0zyiFD1C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000jclpuo87621_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236i12000jcmh8gzB67B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店是这次去广州旅行的超预期惊喜，酒店的瀑布餐厅，云上餐厅和花园酒廊在风景和', '花园酒店是这次去广州旅行的超预期惊喜，酒店的瀑布餐厅，云上餐厅和花园酒廊在风景和食物方面各具特色，水准一流。有设计感精心维护的瀑布花园漂亮精致，很多女孩子拍照打卡。酒店工作人员非常专业，服务暖心细致周到，礼宾部的员工会帮忙收快递客人没有剪刀他们还帮忙拆箱，前台的Lavinia Wu注意到我续订的住房没有酒廊待遇，主动送给我让我在酒店可以享受一致的待遇，酒廊的Jennifer 和Cathy细致温和令人愉快，穿金色亮片的Rain是我离店前最后的美好印象，下次来广州，花园酒店会是我的首选。', '2025-03-29', 5, '[''餐饮设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231f12000jeiv9uh05CE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232h12000jej9px88EBA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234q12000jej3eefE27B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232v12000jej0dp1E7B3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231812000jej3e2dDB35_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235a12000jejbm8h4C00_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000jejhk0l7294_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000jeiu7jp65B9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000jej3e2f2CD0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次主要是带孩子出来玩的，这个酒店很适合带娃玩，酒店25处打卡景点，非常适合泡酒', '这次主要是带孩子出来玩的，这个酒店很适合带娃玩，酒店25处打卡景点，非常适合泡酒店，带娃不累，酒店工作人员都很热情，特别感谢Tina服务特别好！', '2025-04-13', 5, '[''整体满意度'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235e12000jrscrzv309D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000jrrwo0f50BA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000jrsdv7h8FDD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232212000jrrwtwdE50D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次的花园酒店很是满意??酒店硬件无可挑剔，大堂，客房都很有设计感，交通更是方便', '这次的花园酒店很是满意??酒店硬件无可挑剔，大堂，客房都很有设计感，交通更是方便，出门就是地铁站，对我们绿色出行非常便捷[强]前台小姐姐还给我们升级了套房，她家的自助餐更是无话可说[强][玫瑰]', '2025-03-26', 5, '[''交通便利性'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232812000jbhh8kf288D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235s12000jbgghxxF187_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233z12000jbh38wzF9CD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231u12000jbhmrgvBBD9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232812000jbg2jud4871_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '三八节和朋友出游广州入住花园酒店两天两晚，体验非常好。酒店设施古朴，风格典雅，卫', '三八节和朋友出游广州入住花园酒店两天两晚，体验非常好。酒店设施古朴，风格典雅，卫生干净，环境优美，被满满的设计感和中国元素深深地吸引到了。几大亮点突出：酒店大唐富丽堂皇，空间很大，前台的美女帅哥热情耐心快捷，我是钻石会员，给我们送了餐还升级了房间；酒店有四个不同风格的餐厅，我们用餐去了一楼和顶楼，自助餐好吃，服务员热情周到；主楼后面自带花园，亭台楼阁，花团锦簇，四楼还有一个小型博物馆很值得去，因为有感觉参观酒店用了我们半天的时间。总之很满意，再到广州花园酒店是不二之选。', '2025-03-11', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232w12000j0ep17w8535_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234t12000j0egywkF63D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235k12000j0erc8qF462_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236d12000j0ersx41840_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235h12000j0erjx93A8C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000j0ez3bsF9F8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000j0eyzsiF1E5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236a12000j0f4ebf3BF3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '岭南园林中的艺术殿堂 | 入住即享博物馆级体验 ??', '岭南园林中的艺术殿堂 | 入住即享博物馆级体验 ??

??城市绿洲·广府文化·细节控福音

推开花园酒店的玻璃穹顶大门，仿佛踏入一座「会呼吸的艺术馆」——白孔雀雕塑在喷泉旁优雅迎客，20米高的《红楼梦》金箔壁画在长廊流转生辉，每一步都是视觉盛宴。作为住过30+五星酒店的老广，这次入住彻底刷新了我对“奢华”的定义：

? **客房亮点**  
- 入住「粤韵套房」，岭南窗花元素与智能家居融合，迷你吧竟藏着广式凉茶套装，床头柜上的手写欢迎卡是粤绣纹样，细节控狂喜！  
- 180°落地窗俯瞰环市东夜景，浴缸旁配香薰石和精油，泡澡时还能欣赏到花园瀑布景观，妥妥出片圣地。

?? **园林秘境**  
- 被住客称为「隐世花园」的后庭院超出片！锦鲤池、瀑布山石、百年古树构成都市桃源，晨跑时偶遇园丁阿叔热情介绍稀有植物，瞬间get酒店40年历史的温度。

?? **味觉惊喜**  
- 桃园馆的「荔枝木烤乳鸽」让我这个老广竖起大拇指，米其林水准果然名不虚传  
- 意外发现大堂吧有「广府下午茶」，鸡公榄造型点心+西关风情器皿，服务生小哥还会讲解每道茶点的故事

?? **服务彩蛋**  
- 礼宾部竟然有「隐藏服务」！主动提供手绘版《周边美食地图》，连肠粉店的火候差异都标注清楚  
- 退房时收到装着小羊的伴手礼，经理说「希望您把岭南小羊带回家」，这波文化输出我给满分！

最后的最后感谢?viria的热情接待', '2025-03-25', 5, '[''整体满意度'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232d12000jb3cj1l3099_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000jb5dnwoC80D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234j12000jb5ex4f9104_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231f12000jb5fw5eFB9A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店是中国仅有的3家白金五星级酒店其中的一家，处处彰显其作为白金酒店的优', '广州花园酒店是中国仅有的3家白金五星级酒店其中的一家，处处彰显其作为白金酒店的优雅高贵，以及典雅传奇。大堂的背景墙是用金打造的“红楼梦”壁画，有石刻画手漆画等，酒店自带的园林，瀑布、亭台楼阁、小桥流水等自然景象，酒店内就是一个旅游景点，美不胜收，小朋友喜欢。
还有比较值得一提的就是它们家的餐厅了。荔湾亭、瀑布餐厅、桃园馆、名仕阁、凌轩阁都是很不错的选择（一楼早餐厅晚去需要排队）。', '2025-03-25', 5, '[''公共设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0202w12000javxqgb901A_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0232312000jav1w218E6B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '记得20多年前就经常住花园，后新连锁酒店雨后春笋，就很少再住花园了，这次入住，更', '记得20多年前就经常住花园，后新连锁酒店雨后春笋，就很少再住花园了，这次入住，更新改造后的花园一如既往的非常豪横，给升级房型，赠送早餐，送果盘，送口罩，送送送.......，服务超级给力，令人耳目一心，但遗憾的是，西侧修地铁，从早上7点到凌晨零点，噪音巨大，当然这怪不得酒店，只是提醒办理入住时，一天要求房间要朝向环市东路一侧，否则，心理会留下阴影。', '2025-02-21', 5, '[''前台服务'', ''安静程度'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0201s12000inqycliF5B1_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0234m12000inqak915397_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234o12000inpxqyo4BC0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000inq1zxm56D4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236r12000inqwosu6C38_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235f12000inqn0lf6998_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232f12000inqc3y00631_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000inq14ji5E16_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232f12000inqmrya3238_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231b12000inqlbi2A600_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '怎么说呢，一次很满意的入住，从前台到服务中心从客房到礼宾，都是非常专业的服务，酒', '怎么说呢，一次很满意的入住，从前台到服务中心从客房到礼宾，都是非常专业的服务，酒店呢环境优雅美丽，软件很到位，只是硬件有待提高就更完美了', '2025-04-08', 5, '[''前台服务'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231212000jncf08r5D1F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000jncf1c78AF3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '趁老公生日的机会，选择在花园酒店度过愉快的一晚，红棉套房套餐体验很好，提前备注酒', '趁老公生日的机会，选择在花园酒店度过愉快的一晚，红棉套房套餐体验很好，提前备注酒店帮忙做了生日布置，还送了小蛋糕。各个工作人员都很热情，特别是行政酒廊Louis服务热情。', '2025-03-14', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230n12000j2ugpfhDA71_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233d12000j2ub0px9904_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236k12000j2uutbv47BC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '过年期间商务出差二次入住。最后那次入住房间有股经久不散的异味，适逢家属患有中重度', '过年期间商务出差二次入住。最后那次入住房间有股经久不散的异味，适逢家属患有中重度鼻炎，十分不适。所幸反馈给酒店后，客房经理马上上房间处理并第一时间帮我们换房，随后赠送了迎宾水果作为诚意。虽然此前订单中我已特别备注，入住被安排到有异味的房间，到换至新的房间时已差不多15点半，家属第二天要长时间外派出行还是稍有不悦，但所幸酒店反应迅速，态度积极热情，努力为客人解决问题，毫不推搪，又令我对该酒店重拾信心。希望下次安排入住时能参考一下客人备注需求，继续保持酒店在老广、来穗游客心中的形象和地位，下次出差时，会再次三刷体验。ps，酒店的行政礼遇不错??，品种虽少但出品保证，环境不错经常有人拍照留念，值得打卡。', '2025-02-23', 5, '[''客房服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231p12000ip4qkl5C90E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231o12000ip552h99E6E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧叫花园酒店，随处可见的花花，令人心旷神怡～外面看着很大气，一进去给人富丽堂皇', '不愧叫花园酒店，随处可见的花花，令人心旷神怡～外面看着很大气，一进去给人富丽堂皇的感觉，房间干净整洁、设施都不错。酒店内部花园有瀑布有池塘，孩子很喜欢。酒店博物馆有时间的话值得一看。很感叹于一个开业这么久的酒店能维护得这么好，酒店管理的水平相当高??', '2025-03-31', 5, '[''整体满意度'', ''房间设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232y12000jfyqa3tD1A5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231412000jfyxioy2852_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236u12000jfy6vga20BA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230d12000jfz0bw6532C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232a12000jfyvql892AA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务真不错，因个人原因导致没到前台退押金，我又回家了，但是工作人员积极协调，很人', '服务真不错，因个人原因导致没到前台退押金，我又回家了，但是工作人员积极协调，很人性化的帮我处理了，坐了4晚感觉真不错，环境，设施，卫生，服务都很满意。', '2025-03-21', 5, '[''前台服务'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0236512000j7z3t5t25A1_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231312000j7z3r8j421E_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232d12000j7z45ap476B_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店是这次广州行的最大惊喜，真的是惊喜多多。首先硬件无可挑剔，交通方便，门外', '花园酒店是这次广州行的最大惊喜，真的是惊喜多多。首先硬件无可挑剔，交通方便，门外就是地铁站。无论大堂还是房间得设施真的是感觉非常棒，免费升级房间、赠送早餐、享用行政酒廊、收到生日蛋糕……，真的贴心。服务真的一级棒，可以说每个服务员都是经过专业的培训，要夸赞花园酒店的管理层真的不错呢！要夸赞行政酒廊的Carrie和Blair，真的是笑容服务，会和客人温柔的聊天，很有亲和力。园子里的锦鲤也是超好看，下次去广州还会住这里！', '2025-02-19', 5, '[''整体满意度'', ''前台服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0231512000im0h1pb01C2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234n12000im0pxuz0BCC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232812000im0pw39B411_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235j12000im0pxv1D6D1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231d12000im0syz7080B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234l12000im0nkaaD7B4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231v12000im0l7x58687_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230e12000im0ebjbAA9C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000im0l7x71EF0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境：不愧是花园酒店，后花园和瀑布太美了。', '环境：不愧是花园酒店，后花园和瀑布太美了。
服务：态度很好，大部分人都主动打招呼、提供帮助。入住时小姐姐还帮我们升了套房，非常感谢。
卫生：很不错，很放心。
设施：全皮办公桌椅很气派，但可能是太久了，卫生间的马桶圈小了一圈，还晃来晃去不合适，和整体风格格格不入。一个洗手池下水极其缓慢，另外一个洗手池下水也很慢。', '2025-02-16', 4, '[''房间设施'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0233g12000ijwww2c9660_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000ijwtiji38AE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231712000ijwzxp856F3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230d12000ijxejz7E447_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000ijxkrlmC2B9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231912000ijxejz9E686_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店房间干净、卫生。酒店本身自带的花园非常漂亮，瀑布餐厅早餐品种丰富。打扫房间的', '酒店房间干净、卫生。酒店本身自带的花园非常漂亮，瀑布餐厅早餐品种丰富。打扫房间的东南亚小哥认真负责。酒店边上就是淘金地铁站，外出方便。周边吃饭餐馆选择多，以后来广州还会选择花园酒店。

另外酒店有直达香港，澳门的巴士，去港澳非常方便。', '2025-02-20', 5, '[''卫生状况'', ''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0231b12000in4zau2DD93_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232c12000in52vvv6087_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店是中国星级酒店的代表，三家白金五星级酒店之一，大堂气派，尽管酒店很有历史', '花园酒店是中国星级酒店的代表，三家白金五星级酒店之一，大堂气派，尽管酒店很有历史，设施并不陈旧。红棉大床房对于家庭出行很方便，客厅有专门的写字桌和台灯，孩子晚上方便写会作业。早餐选择的30层旋转餐厅，虽说味道一般，但是感觉还不错。周边交通方便，吃喝逛都很方便。总体来说，性价比很高，值得推荐。', '2025-02-10', 5, '[''性价比'', ''周边配套'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234b12000ifsp5450E8E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233412000iftpxwrC9F3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235412000ifto5gc1B58_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231312000ift50gnB97E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237312000iftn76fDA17_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '带着老人小孩出行，前台办理入住没有排队，帮我两个房间都升级了套房。30楼旋转餐厅', '带着老人小孩出行，前台办理入住没有排队，帮我两个房间都升级了套房。30楼旋转餐厅的早餐还不错，各种样式的菜都有。旁边就是淘金地铁站，出门打车也很方便。酒店出去右手边有个点都德不远。对面有个购物中心，很方便', '2025-02-20', 5, '[''前台服务'', ''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0234312000in5ukniABE9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000in5jgqf339A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233g12000in5kscoBE05_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235a12000in5fkvr0423_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000in5jgqhB7ED_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店很高大上，考虑了康莱德和白天鹅，最后还是选这里，也因为白金五星的历史感。花园', '酒店很高大上，考虑了康莱德和白天鹅，最后还是选这里，也因为白金五星的历史感。花园和博物馆都不错，博物馆很有情怀，不虚此行。
早餐很好，选的30层旋转餐厅，大部分菜品味道在线。晚餐是荔湾亭点心半自助，以一个外省人的角度很好吃。
健身的地方有点不好找，但设施还行，该有的都有，不大。
停车不方便，地下停车场离大厅有距离，地上停车场又比较小，自驾游可能要考虑下停车的预案。门口就是地铁站，地铁很方便。
花园双床房非常小，小到唤起我对某些日本酒店的印象：地上能不能平铺开行李箱？能平铺开就算是大房间。按这个标准，这里的也算大房间。但如果再住这里的话，我不会选基础房，俩大人带个孩子太局促了。
有点逗的是晚上22-23点房间出现高频断续刺耳异响，我推断是某些房间用水或者是上下水导致的水管尖锐鸣声。当时孩子已经睡了，俩大人面面相觑，客房服务人员A来的时候没响，她说自己很忙，也没法停留五分钟听一下到底是什么声音，解决方案是要么我们自己内线拨0沟通换房，要么她送耳塞过来。我们的诉求是请她优先解决声音问题，解决不了再换房，毕竟孩子睡着了，不太想折腾。过了一会来了个客房服务B，只送来一副耳塞并且当场听到了连续且刺耳的声音，说立刻回去报告，然后就没有然后了。俩成年人一副耳塞，问题也假装不存在，大半夜大家可能都比较累，凑合睡吧。', '2025-02-08', 4, '[''房间设施'', ''客房服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0232m12000iee56tfBA99_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236k12000iedr9xd8241_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000ieddjzaF0B6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很好，早餐也不错，品种齐全，楼顶旋转餐厅视野无敌。花园太美了，散步根本不想上', '房间很好，早餐也不错，品种齐全，楼顶旋转餐厅视野无敌。花园太美了，散步根本不想上楼。无论晴天阴天，白天还是夜晚，都好适合散步。
游泳池是露天的，但不恒温。
器械也可以。24小时
下次还来', '2025-02-23', 5, '[''餐饮设施'', ''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236312000ioze5h0DE96_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233j12000iozcgit8274_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000ioyirngFD47_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231d12000ioyswww0874_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236812000ioypyu2766D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237412000ioypyu4D8A2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235k12000ioz5tk6D023_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000ioz9wgkA6E0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000ioz0p5l080C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '首先说说地理位置，酒店位于广州的越秀区，周边有商场及饭店吃喝都很便利，酒店门口就', '首先说说地理位置，酒店位于广州的越秀区，周边有商场及饭店吃喝都很便利，酒店门口就有一个地铁站无论是坐公共交通还是打车都很方便。 再说说环境，酒店非常大还自带一个后花园饭后散散步十分惬意，除此之外酒店的四楼还有一个关于酒店历史的博物馆住店客人是免费的值得一逛，房间和公共区域都非常干净。 所有的服务人员都非常礼貌、看到客人都会主动打招呼，即便春节期间入住客人非常的多但服务人员的精神面貌都非常好！ 最后来说说房间，卫生情况是不需要担忧的非常干净，但毕竟是1985年就开业的酒店，房间的布局及设施稍稍落后了一些，没有USB插头、吹风机还是最老式的那种，洗浴后没有能放干净换洗衣物的地方，且浴室及床之间仅有一扇透明的隔门（建议稍稍改进一下）。但总体来说酒店很棒，如有机会再次来广州一定还会选择花园酒店', '2025-02-14', 4, '[''房间设施'', ''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0235d12000iizo4qnE6BF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230z12000iizjych9F24_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234712000iiyyetwFE52_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000iizc8urBF3E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000iiz2eqb09CB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000iizkg6y92B6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000iizjusfC75F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235f12000iizk2xwB718_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务：前台接待的小姐姐服务超级赞，帮我们从红棉升到了海韵，送了两支鲜花，给我们介', '服务：前台接待的小姐姐服务超级赞，帮我们从红棉升到了海韵，送了两支鲜花，给我们介绍了酒店、酒店套餐、博物馆和周边交通，很暖心。
住：房间整体不错，床品很舒服，房间除了没有浴缸外，其他都不错。
吃：早餐和其他五星相比品种不多，胜在瀑布餐厅环境不错；酒吧外国人比较多，有驻唱歌手，唱得很棒，但鸡尾酒很一般。荔湾亭菜品不错，说古很有传统特色，但服务员之间频繁相互呛声，稍显不够友爱。', '2025-02-10', 4, '[''前台服务'', ''房间设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232612000ifpamjsDA6F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231z12000ifo3s7oD26E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000ifo5q3cC7FE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000ifnys4sA368_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000ifok2kz2F06_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235w12000ifoywkc7D95_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234112000ifod14s117A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '8年前曾经住过的酒店留给我很好的印象，所以这次来广州旅游一定要再体验一下。酒店位', '8年前曾经住过的酒店留给我很好的印象，所以这次来广州旅游一定要再体验一下。酒店位置很方便，地铁淘金站出来就到了，马路对面就是广州酒家和友谊商店，附近还有点都德。这次订的花园大床房，房间虽不大，但布局合理，送了欢迎水果：苹果香蕉沙糖桔很甜，房间里有胶囊咖啡机，和川宁茶包，提供的水是屈臣氏绿瓶矿泉水。早上10点到的酒店，被告知要下午2点才能入住，所以到门口寄存处把行李寄好就到对面广州酒家喝早茶去了。在此要表扬寄存处的工作人员（外籍）很有礼貌，很有绅士风度。还有进出酒店都有门童帮忙拉门并热情打招呼，这都是酒店留给我的好印象，并且一直保持到现在，真的是很不容易！不愧是老牌超五星酒店的优良传统，希望一直保持下去。（忘记拍照了，放几张广州夜景照）', '2025-02-23', 5, '[''整体满意度'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235f12000ip244gbBABC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231d12000ip14ifp8798_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233f12000ip19xfq62C2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236012000ip1jiju6D69_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星级酒店，高质量体验和床品用品，窗外风景充满老广州风情，周边美食丰富，环境', '老牌五星级酒店，高质量体验和床品用品，窗外风景充满老广州风情，周边美食丰富，环境优雅，出门地铁站，商务出差不二选择', '2025-04-15', 5, '[''整体满意度'', ''周边配套'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0233512000jtfxsyt2BB3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233712000jtfsijxF1FB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235v12000jtfu8xaA38C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前台小哥Kasas很棒，升级套房，两个早餐，表扬一下。', '前台小哥Kasas很棒，升级套房，两个早餐，表扬一下。
环境地段不错，可是下面在修路，早上八点就开始吵到中午12点，基本不用休息了。
设施太老旧，勉强合格，不能抱太大期望，毕竟老牌五星。
早餐种类多，还行。
总经理不行，啥房费没得赔偿了。', '2025-03-15', 3, '[''前台服务'', ''安静程度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231812000j3f5n3aD839_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235v12000j3f6hg34BCA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000j3foyj84F1B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '超预期的好评，也感叹40年用心经营的本土酒店品牌也可以很棒。因为过年带父母和孩子', '超预期的好评，也感叹40年用心经营的本土酒店品牌也可以很棒。因为过年带父母和孩子一起到广州旅行，去之前几乎在携程上把所有千元左右的广州五星酒店做了研究，重点看了差评，起初还有些担心，因为有评论说酒店设施老旧、服务不够周到等等，所以我订了2晚花园，同时订了1晚价格比花园略高的国际连锁君悦，负责任地说，花园完胜，第一次在携程上给住过的酒店写评价，所谓国货之光，花园值得拥有。一是40年的历史文化积淀，让花园在广州五星酒店里成为综合性价比翘楚。地处老城区越秀，其实去哪里都很方便，特别适合带孩子老人来。酒店占地广，气派，还拥有独立的花园，4楼开辟出了酒店博物馆，彰显白金酒店的荣誉和情怀。老人和孩子一定特别喜欢。二是有人情味的服务。服务员非常多，引导车辆的、殷勤开门的门童、热情存取行李的礼宾、随时关注你拍照、问询需求的大堂引导都不必说，而且，那么大的酒店、那么多楼层，竟然每层都有个人随时提供服务，餐厅和酒店各处中英切换的外籍服务员也很多，连后花园的池子里都没有飘落的落叶，因为有三个身着花园工装服的工作人员一直在打扫……看得出来，每个工作人员都认真负责，我女儿说：“花园酒店里的锦鲤都很热情，一点不怕人，脚步声到哪里，锦鲤就跟到哪里。”是的，我女儿还第一次摸了锦鲤头。三是贴心的服务，努力让顾客获得最佳体验的初心不是随便说说，是做到了！因为订了两个大床房，所以我希望能挨在一起，同时希望安排安静的房间。真的，都满足了的。而且，入住时因为跟引导沟通有误，现场的客人太多了，导致2点办理入住时并没有马上排到房间。我抱怨了一句，听说我下午3点30约了景点导游，前台马上送了我一个下午茶，我就带着父母孩子去水吧喝咖啡、吃水果、吃蛋糕，点心和服务都很棒，当天晚上入住的时候还送来了一份欢迎水果，酒店的用心和细心可见一斑。因为酒店入住客人多，每个楼层都放了早餐就餐指引，还有工作人员现场解说，告诉我们可以到不同的三个餐厅用餐避免拥堵。四是当然也有不足，但瑕不掩瑜，如果5分满分，我仍然愿意给到4.9分。40年的房子，我住的大床房并不大（跟后面住的君悦比，但君悦真的只能是房间大点，其他软硬件差远了），房间尽力维护了，隔音是很好的，但里面有些设计是鸡肋，比如大床房的浴缸，放在梳妆台前，挡道且容易溅水到床上，拥挤；厕所和淋雨室共用一道移动门，很尴尬；有些角落还是没有打扫干净，比如放胶囊咖啡的盘子。荔湾亭价格和品质不符合，服务虽好，但没有主动告知住店客人可以打折。促使我写这条长长评论的原因是，网上刷流量的一些评价，让我行前顾虑重重，保底订了一晚君悦（携程评分比花园高），两家都住了以后，我还是觉得，作为一个中国人，应该有基本的“中国人不骗中国人”的自觉，以及国货自信，花园几乎有三分之一的客人是外国人，而6号我在君悦早餐时，差不多上座5分之四的餐厅，一眼看去外国人只有2个，所以，国际友人比我们会用脚投票，而我们太容易被刷来的流量绑架，如果下次再来广州，我一定再选花园酒店，白金品质，用心经营。（欢迎大家去看我对君悦的对比评价，真的，我必须对刷流量说不，因为广州君悦，我不会选任何一家君悦，因为徒有其名，所谓国际连锁，更像个旅馆）。', '2025-02-06', 5, '[''整体满意度'', ''性价比'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235e12000icu9xxx0A53_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000icteum08C76_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230j12000ict0qoi68DC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店环境优美，特别是后花园的小桥流水，假山瀑布，花草非常漂亮。服务一流，服务员主', '酒店环境优美，特别是后花园的小桥流水，假山瀑布，花草非常漂亮。服务一流，服务员主动帮忙按电梯、拿行李和带路，还免费升级房间。设施非常齐全，卫生干净整洁！是商务旅游的首选！', '2025-03-12', 5, '[''整体满意度'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0233n12000j1ddlweC4CD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000j1ddozmC796_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000j1d6fi1420B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店环境整体设计很有特色，交通非常便利，淘金地铁站出门就是，打车也非常方便。', '花园酒店环境整体设计很有特色，交通非常便利，淘金地铁站出门就是，打车也非常方便。房间干净、整洁，所有服务人员都很礼貌热情，特别感谢行政酒廊的服务员，帮我打印了好多文件，非常感谢！', '2025-03-19', 5, '[''交通便利性'', ''卫生状况'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230p12000j6if2uwE866_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233i12000j6hhef59589_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236a12000j6h63579BFD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233412000j6hnz9qC45F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235912000j6inp683D9A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000j6hyau3839D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000j6ig48cF1F7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232312000j6h4ei0F00A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236112000j6ihgct2CB7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一座有历史的酒店??，有酒店博物馆，有美丽的后花园。早餐丰富好吃??，服务人员很', '一座有历史的酒店??，有酒店博物馆，有美丽的后花园。早餐丰富好吃??，服务人员很多，营造出宾至如归的氛围，很满意。美中不足的也是历史的缺憾，客房很干净，打扫及时，就是硬件设施有点陈旧，有点问题的设施跟前台服务反应后工程部也能及时修理处理，并有联系卡，值得表扬。', '2025-02-08', 4, '[''整体满意度'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234t12000ie1nsk67C84_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232812000ie1r0qr3073_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v12000ie0w27fF581_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236612000ie25ynuEFBA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000ie0znmo8F07_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '春节期间 价格翻倍 普通大床什么的已经没了，定了个城央绿意房型，外面就是这样的景', '春节期间 价格翻倍 普通大床什么的已经没了，定了个城央绿意房型，外面就是这样的景致，还比普通房型贵。虽然是岭客会员金卡，但是由于房满，所以也没有升级房型，送了行政酒廊和早餐，但是早餐人太多要排队，第一天我们出去吃了，第二天起个早不排队了但是也是真的不好吃。房间类似于比较老的快捷酒店，完全没有五星酒店的舒适度，浴缸袋子也没有，我们自己叫了外卖，对了外卖要去楼下外卖柜拿。说实话800一晚非常不值更别提春节1400+每晚的价格，旁边就是全季，和老公说，还不如住全季了', '2025-02-10', 3, '[''性价比'', ''房间设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234l12000ifw6l4tDCB9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233912000ifwrswc8353_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000ifwnw77AD28_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '预定之前其实是很纠结的，怕酒店年代久远房间设施跟不上。结果到了以后，发现各方面简', '预定之前其实是很纠结的，怕酒店年代久远房间设施跟不上。结果到了以后，发现各方面简直超出预期。酒店的外观和大堂超级豪华，就算春节期间服务员的服务也是比较跟得上的，就是办理入住稍微慢了一点。订的红棉大床房，房间很大，住着很舒服。酒店地理位置不错，附近找各种吃的都很方便。', '2025-02-04', 5, '[''房间设施'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232c12000iaslx4mF6EF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000ias1u1dC8E4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧为三家白金五星之一，景色漂亮，服务热情，房间宽敞，没有看出网上说的老旧，只体', '不愧为三家白金五星之一，景色漂亮，服务热情，房间宽敞，没有看出网上说的老旧，只体验到了年代感带来的厚重，比较遗憾的是因为广州实在太好吃了和春节泰安门停业的原因，没有选择在酒店用餐，错过了瀑布餐厅和旋转餐厅，
作为酒店同行参观了住宿业博物馆，对酒店业的发展颇为自豪，祝中国的酒店行业越来越好，服务管理越来越专业', '2025-02-06', 5, '[''整体满意度'', ''景观/朝向'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236c12000icbhjyp0F17_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h12000icaqqufB829_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234012000icby8snBD4D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '总体还是很满意的，酒店后花园很美，大堂气派有老牌五星的风格，酒店门口一直有出租车', '总体还是很满意的，酒店后花园很美，大堂气派有老牌五星的风格，酒店门口一直有出租车等候外出很方便。房间洗澡水大，床品很舒服睡眠很好，提供质量很好的肥皂我很喜欢，现在很多酒店都是洗手液。饮用水也很不错，服务也很好有求必应也都会主动打招呼。小缺点就是房间较小，所以做成了开放式卫生间，马桶间和淋浴间空间就比较小，墙纸因为年久也有些旧，不过装修风格我还是喜欢的。早餐比较一般，品种不算少，但未见广州特色，好歹弄个叉烧包啥的呢。早餐可以在1、3、30楼吃，推荐30楼旋转餐厅吃，视野好每桌有间隔。', '2025-02-05', 4, '[''房间设施'', ''整体满意度'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0236c12000ibkamgn42AC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234m12000ibkiaxxFDA6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237312000ibjusp70FDA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235r12000ibkhbjf5716_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235b12000ibk7uekE607_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233m12000ibkriqd02A1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234x12000ibktw27CAFC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000ibkh88z5CF3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235912000ibk6er2FC86_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老酒店的缺点就是卫生死角太多打扫不仔细，房间灯上全是灰茸太恶心了??洁癖慎住！加', '老酒店的缺点就是卫生死角太多打扫不仔细，房间灯上全是灰茸太恶心了??洁癖慎住！加上房间不像新酒店那么宽敞。入住时没有介绍早餐，其实有三个地方可以吃早餐，但是问工作人员几位口径居然都不一致，完全不太了解一样！这点很差！瀑布餐厅是无猪肉餐厅，早餐很简单寡淡。但是酒店的其他方面还是不错的，过年期间很有年味，服务人员也都比较有礼貌。楼上还有博物馆但是非得扫码注册才能进，很麻烦，建议住店人员直接刷房卡进。2楼荔波亭餐厅实测比3楼桃园口味更好！桃园餐厅不建议！', '2025-02-08', 3, '[''卫生状况'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235x12000iehwxnl1806_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '春节带娃和老人去广州游玩，入住花园酒店，地铁5号线淘金站A出口，非常方便。双床房', '春节带娃和老人去广州游玩，入住花园酒店，地铁5号线淘金站A出口，非常方便。双床房的房间不大，设施略显陈旧，但是酒店的环境不错，带娃看了花园瀑布，池子里的鱼都很大了，预约参观了酒店的博物馆，了解了酒店业的发展历史，瀑布餐厅和30楼的早餐到11点，人多需要排队拿号，最推崇的是酒店服务人员的贴心服务，看到我们饮用水都喝完了，特意写了卡片，帮我们多放了两瓶水，真的感受到了贴心和用心！', '2025-02-03', 4, '[''前台服务'', ''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235j12000i9ya685D445_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230a12000i9y9rqo6E03_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0235012000i9y9yc92CAA_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0235412000i9y6nk72946_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230y12000i9y6ah69BFA_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230l12000i9y6u8c3C5D_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233p12000i9y734zCEE7_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230712000i9yanfhB72B_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0236412000i9yaweo7BEA_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '作为一家老五星酒店，腔调还是有的，房间设施维护的也不错，地理位置也很方便，但有几', '作为一家老五星酒店，腔调还是有的，房间设施维护的也不错，地理位置也很方便，但有几点感受可以给大家做个参考：
1、服务十分机械化，流程很长，就是那种星级酒店的繁琐且不会变通，实用性不多，比较鸡肋；
2、朝向马路那一面的房间，晚上还是很吵的，车流鸣笛声比较影响睡眠，睡眠质量不好的千万别选；
3、早餐真心很一般，418一位/日的价格，性价比无极低，真的没有外面随便一个老铺子做的好（点了早餐外卖比较过），订房千万别选含早餐的；而且如果预约了景点，来不及进去吃要打包的话，还要按他们的标准，标准就是几个非常不好吃的牛角包面包而已，几百块买这些东西，真是奇迹；
4、因为睡眠浅和酒店沟通过三次不要朝向马路的房间，结果还是给了朝向马路的。前台说是朝外花园的，但你们外花园旁边不就是大马路吗？而且订单中备注的小朋友床围也完全没有准备，甚至都没提及，不知道是真的没看见还是当做没看见；
5、不知道是不是春节期间房间紧张，给了朝马路的房间便罢了，而且还是个尾房；以前总听同事提起不要住尾房，但我想着春节期间尽量不找麻烦，所以就没说什么。但是重点来了，真的睡不好，各种奇怪的梦各种醒，每天起床都疲惫不堪。我原以为是自己睡眠不好，结果我那睡觉如小猪的8岁女儿，每夜也是翻来覆去至少醒三次，以至于黑眼圈和浮肿都出来了。以前带她旅游从未如此，建议大家还是谨慎的点吧。
总之，体验感不好，可能之前对花园酒店期望太高了。', '2025-02-02', 2, '[''安静程度'', ''性价比'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230312000i9bj1qv0C8F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '超级失望的入住，没有任何服务，春节在大厅搞活动，又吵又乱，根本没有人服务，办个入', '超级失望的入住，没有任何服务，春节在大厅搞活动，又吵又乱，根本没有人服务，办个入住，也一问三不知。考虑到床小，我们要改成大床房，办理入住的服务生告知，只能住双床，加床要三百多。导致我第一晚根本没有睡觉，在沙发上窝了一晚。第二天找到前台经理换了大床房，加了床。最让人无语的是，找到经理投诉，完全是敷衍。总之，没有服务意识的酒店，以后不会再入住了。这个酒店，最大的问题是，没有服务意识，根本没有那种为客人服务解决问题的概念。唯一可取的是景色吧。', '2025-02-24', 3, '[''前台服务'', ''安静程度'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233n12000ipn27u67ACA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232f12000ipnhy4y49D7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235n12000ipnwjo5A99F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次出游安排了3日2夜，预订的红棉房还没有清洁完毕，就安排了粤韵房。', '这次出游安排了3日2夜，预订的红棉房还没有清洁完毕，就安排了粤韵房。
前台服务：一般吧，没有说明清楚入住期间所包含的餐饮或其他新春活动
房间：没有床围可以提供，然后电热水壶问题，经过2次沟通，换了全新的+10支蒸馏水备用，这个很好，为表歉意还送了1份水果+3只羊公仔（因为有3个孩子），服务员唐苓，很好，2个黑衫的经理也很好，知道我退房那天还有亲戚过来一起吃饭，还帮我延迟退房到3点
行政酒廊：下午茶不论服务还是食物出品，都很不友好，晚上的欢乐时光，出品还不错，服务员Carrie很好，特别表扬一下。', '2025-02-04', 4, '[''前台服务'', ''客房服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233b12000iaw6n03758B_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0235g12000iaw6rsz5E19_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233c12000iaw72i8FAD4_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233y12000iaw6o2nC6DF_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231e12000iaw6t6q8A22_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0234q12000iaw7ngj90FE_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230j12000iaw6t75C26F_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0237112000iaw7ip20346_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231h12000iaw766u99D4_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '1.怀旧打卡还是值得的，check in 大年初一也很快。酒店春节有很多活动，年', '1.怀旧打卡还是值得的，check in 大年初一也很快。酒店春节有很多活动，年味足
2.房间干净，设置太老！虽然翻新但是墙壁还是很多水泡后的脱皮，最恼火的是卫生间很小还做了隔断，胖点的住客还是有点局促了', '2025-02-04', 3, '[''退房/入住效率'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236x12000iatz8f84305_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000iatqrpuD839_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000iatss7k7BDE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231h12000iatwmng3AE3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常感谢1月29日晚上及1月30日白天在9层服务的服务人员！由于空调有问题，房间', '非常感谢1月29日晚上及1月30日白天在9层服务的服务人员！由于空调有问题，房间比走廊还冷，反映了之后，29日晚间的服务人员迅速拿来了暖炉解决了当下的温度问题。30日白天的服务人员早饭后又进行了跟进，在我自己都怕叫空调师傅麻烦的情况下，帮我们督促了检修，晚上回来后发现房间温度舒适。感谢各位服务人员对应迅速，工作有交接，行动力满满，让来广州过年的我们有一个美好的开始～谢谢！', '2025-01-31', 4, '[''客房服务'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230412000i7dc1i2248C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星级酒店，如名字一样，花园式环境，交通便利，出门就是地铁口，附近很多美食，', '老牌五星级酒店，如名字一样，花园式环境，交通便利，出门就是地铁口，附近很多美食，个人出行，商务出行都是很好的选择', '2025-04-06', 5, '[''交通便利性'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230m12000jljv1pe9A62_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232c12000jljihgh5DCA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232m12000jlj8v5jAE3A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '对花园酒店情有独钟，印象最深的就是服务好！已多次入住了，今年大年初一和家人入住，', '对花园酒店情有独钟，印象最深的就是服务好！已多次入住了，今年大年初一和家人入住，体验很好??
年初二中午在桃园馆用餐，其间我儿子突然肠胃不适，当时也没告诉我们，他因肠胃绞痛浑身发冷，自己就躺在了在桃园馆外的椅子上，酒店的两女一男三位经理立即上前询问照顾，并进餐厅告知我们！经理们一边照料病人一边安慰我们，还协助我们叫来120，并迅速协助病人登车，实在是太贴心了！无比无比感动感激??????????
到中山医1??院做了必要检查，幸好儿子是急性肠胃炎，打了止痛针后症状明显缓解，我们下午就回深圳了。
晚上10点，我先生接到了花园酒店经理的电话，详细询问病人的身体状况，真是始料未及！这么贴心的服务只能是花园酒店！感激之情再次涌起??????
以后到广州入住酒店，首选花园??????', '2025-01-30', 5, '[''前台服务'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231b12000i6b7uhy9E98_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0234512000i6b8tdiE1DF_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230k12000i6b7zboD1B1_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232z12000i6b8ykv55F8_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0234d12000i6b7uon6536_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0237412000i6b7z5052B6_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0234p12000i6b8gphFF51_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '过年连续入住几天。来之前看评论说入住前台排队等候时间很长。但是我入住当天觉得前台', '过年连续入住几天。来之前看评论说入住前台排队等候时间很长。但是我入住当天觉得前台接柜工作人员速度很快。而且大堂礼仪小姐也会帮忙协助之前办好入住手续的客人领取房卡分流的很好而且主动帮助客人打开拍照大堂的春节装饰。地理位置优越出行门口就是地铁站。早餐一般。酒店中遇到的每位工作人员还是热情大方礼貌的。', '2025-02-01', 4, '[''前台服务'', ''交通便利性'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234512000i88k4w5D9A1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000i88tmtl9F13_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232512000i88wjuj71A0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '超级棒的酒店，超完美的服务。', '超级棒的酒店，超完美的服务。
之前看到有些差评，内心还很忐忑。
可宾馆所处的区位真是无可替代，还是犹豫中选择了这家，结果成为了这次广州行中最佳的选择。
宾馆装修后非常洁净、现代；前台小姐姐贴心地升级了房间；客房服务细心周到，主动提供咖啡和茶(小小举措，特别温馨)；宾馆所有服务人员都很主动热情……', '2025-02-13', 5, '[''整体满意度'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233l12000iicgrf18DF6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌代表性酒店，各个岗位服务人员态度都很训练有素?? 春节氛围很浓，鲜花摆设处处', '老牌代表性酒店，各个岗位服务人员态度都很训练有素?? 春节氛围很浓，鲜花摆设处处都有。入住期间生日还有布置了房间并准备了蛋糕；房间整理清洁James观察细致，还手写留条祝新年快乐；酒店内餐点选择很多元，酒廊的茶点水果每日都有不同，Carrie热情聊天很温暖。周边出行、美食也都特别多选择。酒店博物馆很有特色，也是酒店行业发展难得的记录。唯一美中不足的部分康体设施在维修。', '2025-02-03', 4, '[''前台服务'', ''客房服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234a12000i9wqn6m2639_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000i9wspla4324_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233j12000i9w9tdv523E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000i9wvg9q9211_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000i9wx5mp4A17_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v12000i9vurhm0CB6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232y12000i9w0sv942C4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '对广州老牌子酒店有很多期待，住完广州迎宾馆来到花园酒店，大堂金碧辉煌的绘画很是震', '对广州老牌子酒店有很多期待，住完广州迎宾馆来到花园酒店，大堂金碧辉煌的绘画很是震撼，春节氛围感很好，装饰热闹，还有专门给人拍摄的服务，很赞。大堂春节还有欢乐表演。房间给了升级套房，让我们体验了两种不同的房型很赞。酒店有个小博物馆让我们了解了广州酒店的发展史。花园瀑布很漂亮，喂鱼是一道风景线，孩子很欢乐。每个酒店打卡点都看了一下还是不错的，房间有不同国家的服务生，尽显花园酒店的国际化，房间服务也非常好。水、咖啡、茶都补足。不足之处：房间比较老化，没有足够的USB插口，也没有像莲花山酒店专门放一个多用途转接头。床太软太软，对我要不好的人来说睡眠是灾难，这点建议参考迎宾馆的床简直太舒服了。旋转餐厅服务体验不好，明档下面的地方没有规则，孩子大人要了两次面都被别人拿走，要么有个叫号牌，要么放在旁边等我们来拿。虽然我们现场投诉了，但来道歉的主厨看上去趾高气扬熬的傲气，可能老牌子酒店的服务就是有点高高在上的。咖啡间台拥挤，我被人踩到几次。服务生像是临时招聘，我和他说桌上餐盘收掉，他叫了别人，说他自己有点忙。瀑布餐厅玻璃不干净不能看到美景，明档的面没有楼上好吃。说实在对拥有米其林餐厅的花园酒店自助早餐实在没什么好吃的，我问了连虾饺都没有。口味不如亚朵一碗面和华夫饼。有时候老牌子也要向新品牌学习。花园酒店是广州的一个招牌，还是希望下次来入住有更好的体验。', '2025-01-31', 3, '[''房间设施'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232k12000i6zcdi4A415_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231412000i6xpbdo14B3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231y12000i6yf89y516D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232h12000i6y7whn3A46_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233012000i6z9wvv0241_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236x12000i6y4bh99FA3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y12000i6xd57t710B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000i6xz2co8C2D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230k12000i6yezoo7F92_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '在广州住的四个酒店中最满意的。服务人员多，态度好，临近过年酒店大堂布置的也很喜庆', '在广州住的四个酒店中最满意的。服务人员多，态度好，临近过年酒店大堂布置的也很喜庆。还有个酒店博物馆，可以看挺久，看得出很用心普及酒店知识，很有趣。后院小而精致，瀑布池塘里的锦鲤超级肥大，见人就过来张嘴，哈哈。酒店位置也很不错，出门就是地铁站，对面是白云宾馆和友谊商店。房间设计还不错，基本可以做到关灯全黑。唯一一点就是我的房间在布草间旁边，早上会有点吵。但服务人员的态度抵消了这点，都非常友好，超赞！', '2025-02-02', 5, '[''前台服务'', ''交通便利性'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232r12000i99blopC1C5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236i12000i98fyd48FCC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231712000i981jnxB850_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000i99gu6n6D62_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000i98u9ybCF70_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234q12000i986tt52950_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233f12000i984ub948EB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232h12000i985axy3FCD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '设施：设施齐全，看着都挺新的', '设施：设施齐全，看着都挺新的
卫生：干净卫生
环境：附近就是北京路吃吃喝喝挺多的
服务：挺好的
定的套房客厅好大，房间稍微感觉小了一些些
早餐没去吃，下次去尝尝', '2025-03-04', 5, '[''周边配套'', ''房间设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0236112000ivlepohBFB2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '作为国内白金五星酒店，广州花园酒店也是中国酒店发展历史的重要见证者和参与者。', '作为国内白金五星酒店，广州花园酒店也是中国酒店发展历史的重要见证者和参与者。
总体体验是不错的，房间住宿也很舒适，酒店内有多家各具特色的餐厅。
酒店四楼的博物馆，和酒店后的花园，都是值得一去的景点', '2025-02-07', 4, '[''整体满意度'', ''餐饮设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235s12000idc98yrC18C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233u12000idbkoqn00BA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '带着两个娃住了两晚，体验非常棒！位置特别便利，淘金地铁a口。去逛了西湖花街，看了', '带着两个娃住了两晚，体验非常棒！位置特别便利，淘金地铁a口。去逛了西湖花街，看了越秀灯会，小蛮腰，退房那天去了动物园，避开人流高峰期。可惜是少了一个浴缸玩水。其他都满分。30楼的凌璇阁旋转餐厅好棒，就是有点晒，各种品类丰富又好吃。行政礼遇的欢乐时光也非常棒！闹事里面有这么一个后花园，还藏着大瀑布。真是不住不知道。非常推荐', '2025-01-28', 5, '[''交通便利性'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234f12000i4l6imo35AF_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0235912000i4l5s2iC248_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231d12000i4l6bs603BB_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0235s12000i4l6zfn7CBD_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前年广交会期间住过一次花园酒店，一直念念不忘，这次全家出游果断定了，还是一样感觉', '前年广交会期间住过一次花园酒店，一直念念不忘，这次全家出游果断定了，还是一样感觉很好，酒店虽然有年份了但是房间维护的很好，大厅的春节气氛也很浓厚，让人宾至如归，唯一的缺点就是房间的马桶感觉可以升级一下，还有就是中央空调必须集中供暖或者供冷，不能自己设置。', '2025-02-01', 5, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235g12000i7zaep336CB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i12000i808h33B88D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000i7z9fy35F60_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '过年去广州玩，带了小孩和老人，选择了广州花园酒店，酒店建设很大气，地理位置优越，', '过年去广州玩，带了小孩和老人，选择了广州花园酒店，酒店建设很大气，地理位置优越，出门没多远就有地铁站，5号线淘金站，我们出行都是地铁到哪里都很方便，旁边都是各种吃的，还有商场，超市。进入酒店，年味的气氛很浓，金碧辉煌，还有专人给拍照，大堂还有各种表演，挺热闹的。订的大床房，房间有点小，设施有点老旧，应该订红棉房的，但整体服务还是不错的。酒店里还有个博物馆，记录了花园酒店发展的历史，很大，后面还有个瀑布花园，带小朋友挺好逛的。', '2025-02-05', 4, '[''交通便利性'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230y12000ibpz3qo0AB1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234b12000ibpstse9C97_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e12000ibpwyd2074C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236u12000ibpck393030_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000ibp6fbwC9FB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间还不错，挺大的，还有咖啡机。窗户可以看到外面的景色??Tina的服务很不错，', '房间还不错，挺大的，还有咖啡机。窗户可以看到外面的景色??Tina的服务很不错，飞快帮我完成退房了??', '2025-04-13', 5, '[''房间设施'', ''退房/入住效率'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0235q12000jrmekmz78E6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234b12000jrmixom2E21_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很有文化底蕴的酒店，工作人员服务态度特别好，出行便利，就在地铁站边上，酒店门口也', '很有文化底蕴的酒店，工作人员服务态度特别好，出行便利，就在地铁站边上，酒店门口也一直有排队的出租车。酒店早餐很好吃，特别是在行政酒廊外吃早餐，可以看到花园的喷泉温和小瀑布，很惬意。早餐味道也不错，服务员还会帮忙冲咖啡。就是房间有点小，带两个娃有点局促，不过性价比还是很高的。', '2025-01-27', 5, '[''交通便利性'', ''前台服务'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0232812000i3qj94h808D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231a12000i3ql9wa0CA9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236a12000i3qn2n1E9E6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务： 相当值得白金五星的服务，每一位遇到的工作人员都礼貌真诚， 办理入住的时候', '服务： 相当值得白金五星的服务，每一位遇到的工作人员都礼貌真诚， 办理入住的时候， 主动给我们升级。主动升级房型的酒店，真的是非常大气和有人情味。 从入住到离开，从未提过要好评，但是这个服务值得超五星好评。

环境：毋庸置疑，这是个富丽堂皇的酒店， 唯一入围白金五星的民族酒店， 建立初期就采用德国技术进行污水处理， 广州运动会的官方酒店等等等等， 无论是它的历史底蕴，还是它现在审美品味，都值得二刷三刷！

卫生：很干净，也是可以娃儿穿着背心睡的酒店。

设施：电视非常高清，有多国频道。 窗帘自动，吹风机等措施很棒， 而且， 这家提供的矿泉水也是高品质的， 还有胶囊咖啡机！唯一不足的是酒店的化妆镜，太矮了，要弯着腰化妆。真的太喜欢这家酒店的贵妃榻和迎宾馆的中式沙发了，都是特别舒服！ 配上超高清电视，舒舒服服在酒店看了两部电影，下雨天最快乐的事！

总结： 酒店很赞， 他的花园瀑布餐厅，荔枝湾餐食，还有自身的博物馆，都很值得参观。 这家酒店让我们在广州降温下雨不宜外出的日子，依然室内旅游了羊城。一定会再来的！', '2025-01-30', 5, '[''前台服务'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233912000i5wj2peE048_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000i5wl9oeC499_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236j12000i5x1aa814D4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231512000i5wopl848A3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233g12000i5x7s2gB7B4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000i5x9cye81E2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234612000i5vvsb170FD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000i5xcc8hA228_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232212000i5w6qsw768D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧是老牌五星，久仰大名，第一次入住，酒店主动升级了套房，特别惊喜，好感度倍增。', '不愧是老牌五星，久仰大名，第一次入住，酒店主动升级了套房，特别惊喜，好感度倍增。酒店大堂恢宏气派，设计古色古香，相比珠江新城的现代化，更喜欢花园酒店的中式设计。后花园一步一景，晒着太阳在里面散步特别舒服。4楼的博物馆值得一去。会回住的！', '2025-01-25', 5, '[''整体满意度'', ''公共设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233z12000i26kt8bE21C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234912000i26mr17B99A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000i26jx22AB3B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231p12000i26mmc8DC0F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236u12000i26b052D39B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236i12000i262o8iA9B2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231v12000i26dgpl4916_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234212000i26zoyk7074_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '30多年前，父亲经常在花园酒店对面广州友谊商店出差，本次跟父母一同到广州怀旧之旅', '30多年前，父亲经常在花园酒店对面广州友谊商店出差，本次跟父母一同到广州怀旧之旅，首选花园酒店，满满的童年回忆！感谢入住时Kasas给我们升级了房间，房间装修温馨典雅，极具老钱风，床品舒适，瀑布餐厅就餐也很惬意！退房时，大堂金色衣服LiVen、Rain给我们服务很好，退房效率高。', '2025-04-01', 5, '[''前台服务'', ''退房/入住效率'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232012000jgssu8j05EF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h12000jgsr8f1AE15_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州来过很多次，终于亲自体验了一次评价不一的花园，个人觉得值得好评，环境 布置 ', '广州来过很多次，终于亲自体验了一次评价不一的花园，个人觉得值得好评，环境 布置 房间 餐饮各方面都非常大气 华贵而且价格值得，最重要的是这里的服务人员人情味很足 会主动服务并态度耐心真诚 必须给大堂的ANNA和WAYNE两位帅哥靓女五星好评！', '2025-01-30', 5, '[''整体满意度'', ''前台服务'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0231812000i5gd4q301F8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000i5gw9z1CA86_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237312000i5eptmz4FFA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000i5g0o0iD202_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232y12000i5fkdroCFF8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老店的服务一如既往的的好，来广州就夜泊花园酒店，早饮在白天鹅酒店，也许就是对老广', '老店的服务一如既往的的好，来广州就夜泊花园酒店，早饮在白天鹅酒店，也许就是对老广的那种情怀。时隔七年，是我第四次来羊城，第一次带娃来住，感谢前台接待员帮我升级套房和主动提供儿童洗漱备品。闺女很喜欢瀑布餐厅，餐厅服务员给了小饼干??给小朋友喂鱼，闺女在鱼池玩得很开心，不愿离开.......期待下次还来这家酒店。', '2025-01-25', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230g12000i1qb36l50C4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231812000i1ps97m699B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h12000i1pp6rn55BB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235o12000i1q92beE383_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233v12000i1pqul7C3E9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235612000i1punnw5DCF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星酒店，环境优美，位置优越，大厅富丽堂皇，布置的非常有岭南过春节的气氛。酒', '老牌五星酒店，环境优美，位置优越，大厅富丽堂皇，布置的非常有岭南过春节的气氛。酒店里的几家馆子也非常好吃。1.3米的双床房非常适合亲子游的一家三口。房间有点小，设施旧。淋浴设计的非常不喜欢。', '2025-02-03', 4, '[''房间设施'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233412000ia0rysc0736_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '低楼层客房整体装修不算过时，不过细节欠佳，房门有起皮现象，沙发也显得很旧，坐感不', '低楼层客房整体装修不算过时，不过细节欠佳，房门有起皮现象，沙发也显得很旧，坐感不太舒适。

桃园餐厅菜品味道不错，食材新鲜，但服务质量参差不齐，部分服务人员缺乏专业性，遇到问题不是积极解决，而是试图把责任推给顾客。并且，住房顾客专享的用餐折扣也未主动告知，还是后来友人告知，回餐厅询问，工作人员却表示要顾客主动提才给优惠，一概不承认自己有问题。

入住期间，还因押金不足碰上服务被婉拒的状况。好在客服许经理处理问题及时又专业，让原本不太愉快的经历有所改观。客服打扫的工作人员都很细心。', '2025-04-12', 3, '[''房间设施'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236512000jqsu2gq532F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233q12000jqu7oue0C02_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000jqss66hA170_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '1991年去过这个酒店??、一晃三十多年了、服务一流、各个方面都很棒、非常满意、', '1991年去过这个酒店??、一晃三十多年了、服务一流、各个方面都很棒、非常满意、这次买了套餐、性价比挺高、酒店博物馆和瀑布都很赞??特别感谢一下一个迎宾的美女、因我的手提袋子太重、她非常热心帮我找了一个酒店的袋子给我、谢谢！', '2025-01-23', 5, '[''整体满意度'', ''性价比'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232e12000i0d9gnl9FF5_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0234312000i0dle9uD870_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0235612000i0dg5vw156F_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230112000i0dl50qE977_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0236312000i0dj4s00152_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230k12000i0dkoniF95D_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意的入住体验，酒店的地理位置非常好，交通也很便利，出门就是地铁站，酒店的大', '非常满意的入住体验，酒店的地理位置非常好，交通也很便利，出门就是地铁站，酒店的大堂非常气派，环境很好，见我带着老人和孩子，还升级了房间，房间干净舒适，服务贴心细致，设施一应俱全。非常推荐！', '2025-03-03', 5, '[''整体满意度'', ''交通便利性'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0235612000iuj8z1v9B04_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000iuj2vb835A8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235o12000iuj5u111A3C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230m12000iuip8h048FF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000iujophp7AC5_R_150_150_R5_Q70_D.jpg\" ]"]');